#!/usr/bin/env ts-node
import * as dotenv from 'dotenv';
import * as path from 'path';
import knex from 'knex';

dotenv.config({ path: path.join(__dirname, '../.env.test') });

import { getEnv } from '../src/utils/get-env-variable.util';
import { DATABASE_URL } from '../src/constants/env-variables.constant';

const excludedMigrations = ['20250609221918_add_condensed_features_content.ts'];

async function resetTestDatabase() {
	console.log('🗑️  Resetting test database...');

	try {
		const connectionString = getEnv<string>({ key: DATABASE_URL, converter: String });

		console.log('📡 Connecting to database...');
		console.log('🔗 Connection string:', connectionString.replace(/:[^:@]*@/, ':***@'));

		const url = new URL(connectionString);
		const dbName = url.pathname.slice(1);

		const db = knex({
			client: 'mysql2',
			connection: {
				host: url.hostname,
				port: parseInt(url.port) || 3336,
				user: url.username,
				password: url.password,
				database: dbName,
			},
		});

		console.log(`✅ Connected to database: ${dbName} at ${url.hostname}:${url.port}`);

		const tablesResult = await db.raw('SHOW TABLES');
		const tables = tablesResult[0] || [];

		if (tables.length === 0) {
			console.log('📭 No tables found to drop');
		} else {
			console.log(`🗂️  Found ${tables.length} tables to drop`);

			await db.raw('SET FOREIGN_KEY_CHECKS = 0');

			for (const tableRow of tables) {
				const tableName = Object.values(tableRow)[0] as string;
				console.log(`  🗑️  Dropping table: ${tableName}`);
				await db.raw(`DROP TABLE IF EXISTS \`${tableName}\``);
			}

			await db.raw('SET FOREIGN_KEY_CHECKS = 1');

			console.log('✅ All tables dropped successfully');
		}

		await db.destroy();
		console.log('📡 Database connection closed');

		console.log('🚀 Running migrations...');

		const migrationDb = knex({
			client: 'mysql2',
			connection: connectionString,
			migrations: {
				migrationSource: {
					getMigrations: async () => {
						const fs = require('fs');
						const files = await fs.promises.readdir(
							path.join(__dirname, '../src/migrations'),
						);

						console.log('All migration files found:', files);

						const filteredFiles = files
							.filter((file: string) => file.endsWith('.ts'))
							.filter((file: string) => {
								const shouldExclude = excludedMigrations.includes(file);
								if (shouldExclude) {
									console.log(`🚫 Excluding migration: ${file}`);
								}
								return !shouldExclude;
							})
							.sort();

						return filteredFiles;
					},
					getMigrationName: (migration: string) => migration,
					getMigration: async (migration: string) => {
						return require(path.join(__dirname, '../src/migrations', migration));
					},
				},
			},
		});

		await migrationDb.migrate.latest();
		console.log('✅ Migrations completed successfully');

		await migrationDb.destroy();
		console.log('📡 Migration connection closed');

		console.log('🎉 Test database reset complete!');
	} catch (error: any) {
		console.error('❌ Error resetting test database:', error);

		if (error?.code === 'ENOTFOUND') {
			console.error('');
			console.error('💡 Troubleshooting:');
			console.error(
				'   - Make sure MySQL containers are running on localhost:3336 and localhost:3337',
			);
			console.error('   - Try running: docker ps to see running containers');
		} else if (error?.code === 'ENOENT') {
			console.error('');
			console.error('💡 Migration directory issue:');
			console.error(`   - Looking for migrations in: ${error.path}`);
			console.error('   - Actual location: src/migrations/');
		}

		process.exit(1);
	}
}

if (require.main === module) {
	resetTestDatabase();
}
